(function () {
  "use strict";

  function submitForm(form) {
    var method = form.getAttribute("hx-post") ? "POST" : (form.method || "GET").toUpperCase();
    var url = form.getAttribute("hx-post") || form.action;
    var targetSelector = form.getAttribute("hx-target");
    var target = targetSelector ? document.querySelector(targetSelector) : null;
    var body = new FormData(form);

    fetch(url, {
      method: method,
      body: body,
      credentials: "same-origin",
      headers: { "HX-Request": "true" }
    }).then(function (response) {
      if (!response.ok) {
        throw new Error("Request failed.");
      }
      return response.text().then(function (text) {
        if (target) {
          swapHTML(target, text);
        }
      });
    }).catch(function () {
      if (target) {
        target.textContent = "Request failed.";
      }
    });
  }

  function swapHTML(target, text) {
    if (window.DOMPurify) {
      target.replaceChildren(window.DOMPurify.sanitize(text, { RETURN_DOM_FRAGMENT: true }));
      return;
    }
    target.textContent = text;
  }

  document.addEventListener("submit", function (event) {
    var form = event.target;
    if (!form || !form.getAttribute || !form.getAttribute("hx-post")) {
      return;
    }
    event.preventDefault();
    submitForm(form);
  });

  document.addEventListener("click", function (event) {
    var link = event.target.closest ? event.target.closest("[hx-get]") : null;
    if (!link) {
      return;
    }
    if (event.metaKey || event.ctrlKey || event.shiftKey || event.button !== 0) {
      return;
    }
    event.preventDefault();
    var targetAttr = link.getAttribute("hx-target");
    var target = null;
    try {
      target = targetAttr ? document.querySelector(targetAttr) : null;
    } catch (e) {
      target = null;
    }
    fetch(link.getAttribute("hx-get"), {
      method: "GET",
      credentials: "same-origin",
      headers: { "HX-Request": "true" }
    }).then(function (response) {
      if (!response.ok) {
        throw new Error("Request failed.");
      }
      return response.text().then(function (text) {
        if (target) {
          swapHTML(target, text);
        }
      });
    }).catch(function () {
      if (target) {
        target.textContent = "Request failed.";
      }
    });
  });
})();
